cd /tmp/sv-94ee2a32157b403ebe1143e7cc20c312/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null | python3 -c "import sys,json; d=json.load(sys.stdin); json.dump(d,open('after-cpm-packages.json','w'),indent=2)" && python3 -c "
import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
# Compare
for bp, ap in zip(b['projects'], a['projects']):
    pname = bp['path'].split('/')[-1]
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        bpkgs = {p['id']: p['resolvedVersion'] for p in bf.get('topLevelPackages',[])}
        apkgs = {p['id']: p['resolvedVersion'] for p in af.get('topLevelPackages',[])}
        for pkg in sorted(set(list(bpkgs.keys()) + list(apkgs.keys()))):
            bv = bpkgs.get(pkg, 'MISSING')
            av = apkgs.get(pkg, 'MISSING')
            status = 'unchanged' if bv == av else f'CHANGED {bv} -> {av}'
            print(f'{pname} | {pkg} | {bv} | {av} | {status}')
"

